// src/actions/db-info.ts
async function dbInfo() {
  const dialect = config5.dialect || "postgres";
  const database = config5.database?.database || "unknown";
  console.log("-- Database Information");
  console.log(`-- Dialect: ${dialect}`);
  console.log(`-- Database: ${database}`);
  console.log();
  try {
    const qb = createQueryBuilder();
    const tables = [];
    let tableNames = [];
    if (dialect === "postgres") {
      const result = await qb.unsafe(`
        SELECT table_name
        FROM information_schema.tables
        WHERE table_schema = 'public'
        AND table_type = 'BASE TABLE'
        ORDER BY table_name
      `);
      tableNames = result.map((r) => r.table_name);
    } else if (isMysqlLike(dialect)) {
      const result = await qb.unsafe(`
        SELECT table_name
        FROM information_schema.tables
        WHERE table_schema = DATABASE()
        AND table_type = 'BASE TABLE'
        ORDER BY table_name
      `);
      tableNames = result.map((r) => r.table_name);
    } else if (dialect === "sqlite") {
      const result = await qb.unsafe(`
        SELECT name
        FROM sqlite_master
        WHERE type = 'table'
        AND name NOT LIKE 'sqlite_%'
        ORDER BY name
      `);
      tableNames = result.map((r) => r.name);
    }
    for (const tableName of tableNames) {
      try {
        const countResult = await qb.unsafe(`SELECT COUNT(*) as count FROM ${tableName}`);
        const rowCount = Number(countResult[0]?.count || 0);
        let columnCount = 0;
        let indexCount = 0;
        if (dialect === "postgres") {
          const colResult = await qb.unsafe(`
            SELECT COUNT(*) as count
            FROM information_schema.columns
            WHERE table_name = $1
          `, [tableName]);
          columnCount = Number(colResult[0]?.count || 0);
          const idxResult = await qb.unsafe(`
            SELECT COUNT(*) as count
            FROM pg_indexes
            WHERE tablename = $1
          `, [tableName]);
          indexCount = Number(idxResult[0]?.count || 0);
        } else if (isMysqlLike(dialect)) {
          const colResult = await qb.unsafe(`
            SELECT COUNT(*) as count
            FROM information_schema.columns
            WHERE table_name = ?
            AND table_schema = DATABASE()
          `, [tableName]);
          columnCount = Number(colResult[0]?.count || 0);
          const idxResult = await qb.unsafe(`
            SELECT COUNT(*) as count
            FROM information_schema.statistics
            WHERE table_name = ?
            AND table_schema = DATABASE()
          `, [tableName]);
          indexCount = Number(idxResult[0]?.count || 0);
        } else if (dialect === "sqlite") {
          const colResult = await qb.unsafe(`PRAGMA table_info(${tableName})`);
          columnCount = colResult.length;
          const idxResult = await qb.unsafe(`PRAGMA index_list(${tableName})`);
          indexCount = idxResult.length;
        }
        tables.push({
          name: tableName,
          rowCount,
          columns: columnCount,
          indexes: indexCount
        });
      } catch (err) {
        console.error(`-- Error getting info for table ${tableName}:`, err);
      }
    }
    const totalRows = tables.reduce((sum, table) => sum + table.rowCount, 0);
    console.log(`-- Total Tables: ${tables.length}`);
    console.log(`-- Total Rows: ${totalRows.toLocaleString()}`);
    console.log();
    if (tables.length > 0) {
      console.log("Tables:");
      console.log();
      const maxNameLength = Math.max(...tables.map((t) => t.name.length));
      const padding = maxNameLength + 2;
      const header = "Table".padEnd(padding) + "Rows".padStart(12) + "Columns".padStart(10) + "Indexes".padStart(10);
      console.log(header);
      console.log("-".repeat(header.length));
      for (const table of tables) {
        const name = table.name.padEnd(maxNameLength + 2);
        const rows = table.rowCount.toLocaleString().padStart(12);
        const cols = (table.columns || 0).toString().padStart(10);
        const idxs = (table.indexes || 0).toString().padStart(10);
        console.log(`${name}${rows}${cols}${idxs}`);
      }
    } else {
      console.log("-- No tables found");
    }
    return {
      dialect,
      database,
      tables,
      totalTables: tables.length,
      totalRows
    };
  } catch (err) {
    console.error("-- Failed to get database info:", err);
    throw err;
  }
}
