// src/actions/db-wipe.ts
import process23 from "process";
async function dbWipe(options = {}) {
  const dialect = options.dialect || process23.env.DB_DIALECT || "postgres";
  if (options.verbose) {
    console.log(`Wiping all tables from ${dialect} database...`);
  }
  try {
    let tables = [];
    if (dialect === "postgres") {
      const result = await bunSql`
        SELECT tablename
        FROM pg_tables
        WHERE schemaname = 'public'
      `;
      tables = result.map((row) => row.tablename);
    } else if (isMysqlLike(dialect)) {
      const dbName = process23.env.DB_NAME || "test";
      const result = await bunSql`
        SELECT table_name
        FROM information_schema.tables
        WHERE table_schema = ${dbName}
      `;
      tables = result.map((row) => row.table_name || row.TABLE_NAME);
    } else if (dialect === "sqlite") {
      const result = await bunSql`
        SELECT name
        FROM sqlite_master
        WHERE type = 'table'
        AND name NOT LIKE 'sqlite_%'
      `;
      tables = result.map((row) => row.name);
    }
    if (tables.length === 0) {
      console.log("No tables found to drop.");
      return;
    }
    if (options.verbose) {
      console.log(`Found ${tables.length} tables: ${tables.join(", ")}`);
    }
    if (dialect === "postgres") {
      for (const table of tables) {
        if (options.verbose) {
          console.log(`Dropping table: ${table}`);
        }
        await bunSql`DROP TABLE IF EXISTS ${bunSql(table)} CASCADE`;
      }
    } else if (isMysqlLike(dialect)) {
      await bunSql`SET FOREIGN_KEY_CHECKS = 0`;
      for (const table of tables) {
        if (options.verbose) {
          console.log(`Dropping table: ${table}`);
        }
        await bunSql`DROP TABLE IF EXISTS ${bunSql(table)}`;
      }
      await bunSql`SET FOREIGN_KEY_CHECKS = 1`;
    } else if (dialect === "sqlite") {
      await bunSql`PRAGMA foreign_keys = OFF`;
      for (const table of tables) {
        if (options.verbose) {
          console.log(`Dropping table: ${table}`);
        }
        await bunSql`DROP TABLE IF EXISTS ${bunSql(table)}`;
      }
      await bunSql`PRAGMA foreign_keys = ON`;
    }
    console.log(`\u2713 Dropped ${tables.length} tables`);
  } catch (error) {
    console.error("Error wiping database:", error.message);
    throw error;
  }
}
